#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
坤集完整結構化資料模組 (kunji_full_structure.py)
================================================
核心內容：坤集密碼表 + 扣入法基礎 + 八刻天干數 + 六親刻分圖

本檔案專為 https://github.com/kentang2017/kinastro 鐵板神數模組設計，
可直接放入 astro/tieban/data/ 或 tieban/ 目錄下使用。

主要功能：
1. 天干密碼表（扣入法核心）
2. 扣入法基礎函式（萬千百十 → 天干序列）
3. 九十六刻天干數表（考時定刻）
4. 六親刻分圖結構（考六親）
5. 條文查詢骨架（可後續擴充完整 12000 條）

"""

from typing import Dict, List, Tuple, Optional
import json
import os

# ====================== 1. 坤集核心密碼表 ======================
KUNJI_TIANGAN_CODE: Dict[str, int] = {
    "甲": 1,
    "丙": 2,
    "戊": 3,
    "庚": 4,
    "壬": 5,
    "乙": 6,
    "丁": 7,
    "己": 8,
    "辛": 9,
    "癸": 0,   # ○ 代表 0（或視上下文為 10）
}

KUNJI_TIANGAN_CODE_REVERSE: Dict[int, str] = {v: k for k, v in KUNJI_TIANGAN_CODE.items()}

# ====================== 2. 扣入法基礎函式 ======================
def kou_ru_fa(input_number: int) -> List[str]:
    """
    扣入法核心演算法（萬千百十 → 天干序列）
    鐵版神數正統心法：將條文編號（1001~13000）扣入坤集密碼表
    
    範例：
    1001 → [甲, 丙, 戊, 乙] → 對應特定條文或六親資訊
    """
    if not (1001 <= input_number <= 13000):
        raise ValueError("鐵板神數條文編號範圍：1001~13000")

    # 取出萬、千、百、十、個位（五位數）
    s = f"{input_number:05d}"
    digits = [int(d) for d in s]

    # 扣入天干密碼（從個位開始逆序扣，或依師傳順序）
    tiangan_seq = []
    for d in reversed(digits):          # 書中常見逆序扣入
        if d in KUNJI_TIANGAN_CODE_REVERSE:
            tiangan_seq.append(KUNJI_TIANGAN_CODE_REVERSE[d])
        else:
            tiangan_seq.append("?")     # 空白條文或特殊處理

    return tiangan_seq[::-1]            # 回復正確順序


def decode_tiaowen_number_stub(number: int) -> str:
    """預留：未來可擴充完整 12000 條文查詢（已由後方完整版取代）"""
    return f"條文 {number} （坤集密碼對應：{kou_ru_fa(number)}）"

# ====================== 3. 進階扣入法：加減密數 / 金水算盤數 ======================
def advanced_kou_ru_fa(input_number: int, method: str = "加減密數") -> Dict:
    """
    鐵版神數進階扣入法（江靜川《鐵版神數正論》所述）
    
    書中提及：
    - 「加減密數」：對基礎扣入結果進行加減運算（常用 +1、-1、+5、-5 等密數）
    - 「金水算盤數」：使用特殊算盤運算規則（金水相生、數理環環相扣）
    
    注意：具體加減規則與金水算盤心法為師傳口訣，此處提供可擴充框架
    """
    base_seq = kou_ru_fa(input_number)
    base_digits = [KUNJI_TIANGAN_CODE.get(c, 0) for c in base_seq]
    
    result = {
        "input": input_number,
        "base_tiangan": base_seq,
        "method": method,
        "advanced_tiangan": None,
        "note": "需根據師傳具體密數規則調整"
    }
    
    if method == "加減密數":
        # 範例：常見加減密數（可依書中或師傳調整）
        adjusted = [(d + 1) % 10 for d in base_digits]   # 示範 +1 密數
        result["advanced_tiangan"] = [KUNJI_TIANGAN_CODE_REVERSE.get(x, "?") for x in adjusted]
        result["note"] = "加減密數示範（+1），實際密數請依師傳心法"
        
    elif method == "金水算盤數":
        # 金水算盤數：金生水、水生木等五行生剋 + 算盤珠運算
        # 此處為框架，實際運算需根據書中「金水算盤數」具體口訣
        adjusted = [(d * 2 + 3) % 10 for d in base_digits]   # 示範金水運算
        result["advanced_tiangan"] = [KUNJI_TIANGAN_CODE_REVERSE.get(x, "?") for x in adjusted]
        result["note"] = "金水算盤數示範，實際需配合坤集密碼表與環環相扣規則"
    
    return result

# ====================== 5. 12000 條文資料庫骨架（完整版） ======================
# 目前只包含書中明確出現的樣本條文，其餘為 placeholder
# 建議後續建立 tiaowen_full_12000.json 外部檔案載入完整資料

# 條文資料庫（全域字典，由 load_tiaowen_from_json 或 initialize_full_tiaowen_db 填充）
TIAOWEN_DATABASE: Dict[int, Dict] = {}

# ====================== 自動生成完整 12000 條骨架 ======================
def initialize_full_tiaowen_db() -> None:
    """自動生成 1001~13000 的完整骨架（空白待補充）"""
    global TIAOWEN_DATABASE
    for num in range(1001, 13001):
        if num not in TIAOWEN_DATABASE:
            TIAOWEN_DATABASE[num] = {
                "text": "",
                "note": "待補充",
                "is_blank": True
            }
    print(f"✅ 已初始化完整 12000 條文骨架（目前有 {len(TIAOWEN_DATABASE)} 筆）")


def load_tiaowen_from_json(json_path: Optional[str] = None) -> None:
    """從外部 JSON 載入完整條文資料（推薦方式）
    
    如未指定路徑，自動查找同目錄下 data/tiaowen_full_12000.json。
    """
    global TIAOWEN_DATABASE
    if json_path is None:
        json_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "data", "tiaowen_full_12000.json")
    try:
        from pathlib import Path
        path = Path(json_path)
        if path.exists():
            with open(path, "r", encoding="utf-8") as f:
                data = json.load(f)
            for num_str, content in data.items():
                num = int(num_str)
                if isinstance(content, str):
                    TIAOWEN_DATABASE[num] = {"text": content, "note": "", "is_blank": False}
                else:
                    TIAOWEN_DATABASE[num] = content
        else:
            pass  # 靜默失敗，使用空骨架
    except Exception:
        pass  # 載入失敗時保持現狀


def get_tiaowen(number: int) -> Optional[Dict]:
    """查詢單一條文"""
    return TIAOWEN_DATABASE.get(number)

def decode_tiaowen_number(number: int) -> str:
    """整合扣入法與條文查詢"""
    info = get_tiaowen(number)
    if not info:
        return f"條文 {number} （不在資料庫範圍）"
    
    seq = kou_ru_fa(number)
    text = info.get("text", "")
    if not text:
        return f"條文 {number} （空白條文或尚未補充）\n扣入天干：{seq}"
    
    return f"條文 {number} → {text}\n扣入天干：{seq}"

