# ====================== 5. 完整資料匯出函式 ======================
def export_kunji_data() -> Dict:
    """匯出全部坤集結構化資料（方便存成 JSON 或匯入 Streamlit）"""
    return {
        "tiangan_code": KUNJI_TIANGAN_CODE,
        "tiangan_reverse": KUNJI_TIANGAN_CODE_REVERSE,
        "bake_96_ke": BAKE_96_KE,
        "six_qin_ke_fen": SIX_QIN_KE_FEN,
        "version": "1.0",
        "usage": "扣入法 + 考時定刻 + 考六親",
    }


def save_to_json(filepath: str = "kunji_full_structure.json"):
    """將資料存成 JSON，方便 kinastro 其他模組載入"""
    data = export_kunji_data()
    with open(filepath, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f"✅ 坤集完整資料已儲存至 {filepath}")


